create table practice (
	id INT,
	first_name VARCHAR(50),
	last_name VARCHAR(50),
	email VARCHAR(50),
	gender VARCHAR(50),
	date_of_birth DATE,
	country_of_birth VARCHAR(50)
);



SELECT * FROM practice;

SELECT  DISTINCT country_of_birth FROM practice ORDER BY country_of_birth;

SELECT * FROM practice WHERE gender = 'Male';

SELECT * FROM practice WHERE gender = 'Female';

SELECT * FROM practice WHERE gender = 'Male' AND country_of_birth = 'China';


SELECT * FROM practice WHERE gender = 'Male' AND country_of_birth = 'China' OR country_of_birth = 'Poland';

SELECT 1 = 1;

SELECT * FROM practice LIMIT 10;
--will give the rows uptil 10

SELECT * FROM practice OFFSET 6 LIMIT 5;

SELECT * FROM practice OFFSET 6;


SELECT * FROM practice OFFSET 5 FETCH FIRST 5 ROWS ONLY;

SELECT * FROM practice WHERE country_of_birth IN ('China', 'Poland','Brazil');

SELECT * FROM practice WHERE country_of_birth IN ('China', 'Poland','Brazil') ORDER BY country_of_birth;

SELECT * FROM practice WHERE email LIKE '%.com'; -- % Is the wildcard here

SELECT * FROM practice WHERE email LIKE '%@bloomberg.com';

SELECT * FROM practice WHERE email LIKE '%@goggle.com';

SELECT country_of_birth, COUNT(*) FROM practice GROUP BY country_of_birth;

SELECT country_of_birth, COUNT(*) FROM practice GROUP BY country_of_birth ORDER BY country_of_birth;

SELECT country_of_birth, COUNT(*) FROM practice GROUP BY country_of_birth HAVING COUNT(*) > 5 ORDER BY country_Of_birth; -- COUNT() is an aggregate function, use postgree sql docs for other functions. 

